# Category: business_logic_flaw

def process_payment(user, cart_items, payment_details):
    discount_percentage = {
        'basic': 0,
        'premium': 15,
        'enterprise': 30
    }.get(user.role, 0)
    
    cart_total = sum(item['price'] * item['quantity'] for item in cart_items)
    discount_amount = (cart_total / 100) * discount_percentage
    
    if payment_details['payment_method'] == 'card':
        card_type = payment_details.get('card_type')
        
        # Assume we have a function to process the payment with card details
        process_card_payment(card_type, cart_total - discount_amount)
    
    elif payment_details['payment_method'] == 'paypal':
        # Assume we have a function to process the payment with paypal details
        process_paypal_payment(payment_details.get('paypal_token'), cart_total - discount_amount)

def process_card_payment(card_type, amount):
    # Simulate processing card payment
    print(f"Processing {card_type} payment for ${amount:.2f}")

def process_paypal_payment(paypal_token, amount):
    # Simulate processing paypal payment
    print(f"Processing paypal payment with token: {paypal_token} for ${amount:.2f}")